// Separar paso1 y paso2 (con FIX D 2026-05-19: filtrar mas recientes)
const archivos = ($input.first().json.data) || [];

// FIX D: ordenar por createdTime descendente
archivos.sort((a, b) => {
  const ta = new Date(a.createdTime || a.modifiedTime || 0).getTime();
  const tb = new Date(b.createdTime || b.modifiedTime || 0).getTime();
  return tb - ta;
});

const paso1All = archivos.filter(a => a.name && a.name.startsWith('paso1_'));
const paso2All = archivos.filter(a => a.name && a.name.startsWith('paso2_'));

if (paso1All.length === 0) throw new Error('No hay archivo paso1_Yopago en OUTPUTS');
if (paso2All.length === 0) throw new Error('No hay archivos paso2_Banco en OUTPUTS');

// paso1: tomar solo el MAS RECIENTE
const paso1 = paso1All[0];

// paso2: tomar el MAS RECIENTE de cada banco (Valles y Credil)
const paso2VallesAll = paso2All.filter(p => /valles|lirio/i.test(p.name));
const paso2CredilAll = paso2All.filter(p => /credil/i.test(p.name));
const paso2 = [];
if (paso2VallesAll.length > 0) paso2.push(paso2VallesAll[0]);
if (paso2CredilAll.length > 0) paso2.push(paso2CredilAll[0]);

// Validacion: debe haber al menos 1 paso2
if (paso2.length === 0) throw new Error('No hay paso2 de Valles ni Credil en OUTPUTS (verificar que Script 2 haya corrido)');

return [{ json: {
  yopago: paso1,
  bancos: paso2,
  _stats: {
    paso1_total_encontrados: paso1All.length,
    paso2_total_encontrados: paso2All.length,
    paso1_seleccionado: paso1.name,
