  const v = headerRow.getCell(c).value;
  headers[c - 1] = (v == null) ? '' : String(v).trim();
}
const filas = [];
ws.eachRow({ includeEmpty: false }, (row, rowNum) => {
  if (rowNum === 1) return;
  const obj = { __rowNum__: rowNum };
  let allEmpty = true;
  row.eachCell({ includeEmpty: true }, (cell, colNum) => {
    const h = headers[colNum - 1];
    if (!h) return;
    let v = cell.value;
    if (v && typeof v === 'object' && 'result' in v) v = v.result;
    if (v && typeof v === 'object' && 'richText' in v) v = v.richText.map(r => r.text).join('');
    if (v && v instanceof Date) v = v.toISOString().slice(0, 10);
    obj[h] = (v == null) ? '' : v;
    if (String(v ?? '').trim() !== '') allEmpty = false;
  });
  if (!allEmpty) filas.push(obj);
});
return [{
  json: { filas, headers, sheetName: ws.name, rowCount: filas.length, sheetNameBuscado: sheetName, fallbackUsed: ws.name !== sheetName },
  binary: item.binary
}];

