const ExcelJS = require('exceljs');
const item = $input.first();
if (!item || !item.binary || !item.binary.data) throw new Error('Sin binary del paso2 banco');
const buf = await this.helpers.getBinaryDataBuffer(0, 'data');
_validarXLSX(buf, (item.binary?.data?.fileName || 'banco_paso2'));
const wb = new ExcelJS.Workbook();
await wb.xlsx.load(buf);
const ws = wb.worksheets[0];
if (!ws) throw new Error('paso2 sin worksheets');
const headerRow = ws.getRow(1);
const headers = [];
const colCount = ws.columnCount || 1;
for (let c = 1; c <= colCount; c++) {
  const v = headerRow.getCell(c).value;
  headers[c - 1] = (v == null) ? '' : String(v).trim();
}
// SELECTIVA: leer hasta encontrar separadora salmon (fila vacia).
// Performance: usar eachRow + retornar 1 SOLO item con array.
const filas = [];
let stopped = false;
ws.eachRow({ includeEmpty: true }, (row, rowNum) => {
  if (rowNum === 1) return;
  if (stopped) return;
  const obj = {};
  let allEmpty = true;
  row.eachCell({ includeEmpty: true }, (cell, colNum) => {
    const h = headers[colNum - 1];
    if (!h) return;
    let v = cell.value;
    if (v && typeof v === 'object' && 'result' in v) v = v.result;
    if (v && typeof v === 'object' && 'richText' in v) v = v.richText.map(r => r.text).join('');
    if (v && v instanceof Date) v = v.toISOString().slice(0, 10);
    obj[h] = (v == null) ? '' : v;
    if (String(v ?? '').trim() !== '') allEmpty = false;
  });
  if (allEmpty) { stopped = true; return; }
  filas.push(obj);
});
return [{ json: { filas, headers, rowCount: filas.length } }];

// Read banco XLSX retorna 1 item con {filas: [...]}. Tomar filas directo.
const data = $input.first().json;
const movs = data.filas || [];
return [{ json: { banco_name: $('Loop bancos').item.json.name, movs: movs } }];

// Cruzar y conciliar v2 (UNICIDAD BILATERAL + filtro debito correcto + col D banco)
//
// Reglas:
//  - Solo procesar creditos (col 'debito' = '+'). Descartar debitos ('-').
//  - Conciliar SOLO si el valor es UNICO: aparece exactamente 1 vez sumando todos los bancos
//    Y exactamente 1 vez en las recargas pendientes del Yopago.
//  - Cuando es unico: escribir col D (Banco) con el banco identificado + col E (Confirmado) = 'Si'.
//  - Cuando NO es unico (ambiguo): dejar las celdas vacias para revision manual / WhatsApp.
//  - ID Agencia = 226796 -> col E = 'Ecuabet' (recarga interna, no se cruza con banco).

const yopagoData = $('Aggregate Yopago').first().json.data?.[0] || {filas:[], headers:[]};
const yopagoFilas = yopagoData.filas || [];
const yopagoHeaders = yopagoData.headers || [];
const bancos = $('Aggregate todos los bancos').first().json.data || [];

const ID_INTERNA = '226796';

// Mapea nombre de archivo a etiqueta de banco final (segun listas del Yopago)
function nombreBanco(nombreArchivo) {
  const n = String(nombreArchivo || '').toLowerCase();
  if (n.includes('valles') || n.includes('lirio')) return 'Valles de Lirio';
  if (n.includes('credil')) return 'Coop Credil';
  if (n.includes('pichincha')) return 'Pichincha';
  return '';
}

// Indexar movimientos de banco por VALOR (solo creditos, ignorar reversos)
const bancoPorValor = {};
let totalMovsLeidos = 0, totalMovsCreditos = 0;
for (const b of bancos) {
  const bancoLabel = nombreBanco(b.banco_name);
  for (const mov of (b.movs || [])) {
    totalMovsLeidos++;
    // Usar el header (mov.debito) no un indice fijo - FIX BUG
    const debito = String(mov['debito'] || mov.Debito || mov.DEBITO || '').trim();
    const trans = String(mov['transaccion'] || mov.Transaccion || '').toUpperCase();
    if (debito === '-') continue;          // descartar debitos
    if (trans.includes('REVERSO')) continue;
    const valor = parseFloat(String(mov['valor'] || mov.Valor || '0').replace(/[^0-9.\-]/g, ''));
    if (!valor || valor <= 0) continue;
    const doc = String(mov['documento'] || mov.Documento || '');
    const fecha = String(mov['fecha'] || mov.Fecha || '');
    if (!bancoPorValor[valor]) bancoPorValor[valor] = [];
    bancoPorValor[valor].push({ doc, banco: bancoLabel, fecha });
    totalMovsCreditos++;
  }
}

// Contar recargas PENDIENTES del Yopago por valor (las que aun no tienen Confirmado)
const recargasPendientesPorValor = {};
for (const fila of yopagoFilas) {
  const conf = String(fila.Confirmado || fila.confirmado || '').trim();
  if (conf) continue; // ya conciliada, no la contamos
  const id_ag = String(fila['ID Agencia'] || fila.ID || fila.id || '').trim();
  if (!id_ag) continue;
  if (id_ag === ID_INTERNA) continue; // Ecuabet, no se cruza con banco
  const valor = parseFloat(String(fila['Valor Recarga'] || fila.Valor || fila.valor || '0').replace(/[^0-9.\-]/g, ''));
  if (!valor || valor <= 0) continue;
  recargasPendientesPorValor[valor] = (recargasPendientesPorValor[valor] || 0) + 1;
}

// Stats para el informe
let conciliadasUnicas = 0;
let marcadasEcuabet = 0;
let ambiguas_multiplesBancos = 0;
let ambiguas_multiplesRecargas = 0;
let sinMatch = 0;

const out = yopagoFilas.map(fila => {
  const conf = String(fila.Confirmado || fila.confirmado || '').trim();
  if (conf) return { ...fila };  // no tocar filas ya marcadas

  const id_ag = String(fila['ID Agencia'] || fila.ID || fila.id || '').trim();
  const valor = parseFloat(String(fila['Valor Recarga'] || fila.Valor || fila.valor || '0').replace(/[^0-9.\-]/g, ''));

  if (!id_ag || !valor) return { ...fila };

  // Caso especial: Ecuabet interno
  if (id_ag === ID_INTERNA) {
    marcadasEcuabet++;
    return { ...fila, Confirmado: 'Ecuabet' };
  }

  // Buscar movimientos de banco con ese valor
  const movsConEseValor = bancoPorValor[valor] || [];
  const totalMovs = movsConEseValor.length;
  const totalRecargas = recargasPendientesPorValor[valor] || 0;

  if (totalMovs === 0) {
    sinMatch++;
    return { ...fila };  // sin match: queda vacia
  }
  if (totalMovs > 1) {
    ambiguas_multiplesBancos++;
    return { ...fila };  // ambiguo: 2+ pagos del mismo valor en bancos, dejar para revision manual
  }
  if (totalRecargas > 1) {
    ambiguas_multiplesRecargas++;
    return { ...fila };  // ambiguo: 2+ recargas del mismo valor en yopago, no sabemos a cual asignar
  }

  // UNICO: 1 pago banco + 1 recarga yopago con ese valor
  const m = movsConEseValor[0];
  conciliadasUnicas++;
  return { ...fila, Banco: m.banco, Confirmado: 'Si' };
});

// Devolver con stats para auditar
const yopagoBinary = $('Read Yopago mes actual').first().binary;
return [{
  json: {
    filas: out,
    headers: yopagoHeaders,
    total: out.length,
    _stats: {
      movsLeidos: totalMovsLeidos,
      movsCreditos: totalMovsCreditos,
      conciliadasUnicas,
      marcadasEcuabet,
      ambiguas_multiplesBancos,
      ambiguas_multiplesRecargas,
      sinMatch,
    }
  },
  binary: yopagoBinary
}];

