// === ASEGURAR DATAVALIDATIONS (sin jszip, solo exceljs) ===
function _asegurarDVs(ws) {
  if (!ws) return;
  // Definir las listas de valores permitidos para cada columna
  const BANCOS = 'Valles de Lirio,Coop Credil,Pichincha,Binance,Ecuabet';
  const CONFIRMADOS = 'Si,no,comisiones,prestamo,pendiente,Ecuabet';
  // Aplicar dataValidation tipo lista a las cols D y E de filas 2-500 (cubre con margen)
  // ExcelJS soporta dataValidations.add(range, validation)
  try {
    if (ws.dataValidations && typeof ws.dataValidations.add === 'function') {
      ws.dataValidations.add('D2:D500', {
        type: 'list',
        allowBlank: true,
        formulae: ['"' + BANCOS + '"'],
        showErrorMessage: true,
        errorTitle: 'Banco invalido',
        error: 'Valor no permitido. Debe ser uno de: ' + BANCOS,
      });
      ws.dataValidations.add('E2:E500', {
        type: 'list',
        allowBlank: true,
        formulae: ['"' + CONFIRMADOS + '"'],
        showErrorMessage: true,
        errorTitle: 'Confirmado invalido',
        error: 'Valor no permitido',
      });
    }
  } catch (e) {
    // Si la API cambio, intentar por celda
  }
